// ascii-lartpc.js — drop-in <ascii-lartpc> custom element.
//
// Frame data is gzip+base64 embedded below. To inspect the raw frames:
//   python3 -c "import re,base64,gzip,sys;\
//     s=open('ascii-lartpc.js').read();\
//     b=re.search(r'FRAME_DATA_B64 = \"([^\"]+)\"',s).group(1);\
//     sys.stdout.write(gzip.decompress(base64.b64decode(b)).decode())"
//
// Usage:
//   <script src="ascii-lartpc.js"></script>
//   <ascii-lartpc rotation="6"></ascii-lartpc>
//
// Knobs:
//   rotation  — seconds per full revolution (default 6)
//   fps       — render cap (default 60). The actual frame index is computed
//               from elapsed time and rotation, so high fps just makes the
//               cadence smoother — no extra payload, no interpolation.
//   paused    — presence pauses the animation.

/* DATA_START */
const FRAME_DATA_B64 = "";
/* DATA_END */

let framesPromise = null;
function loadFrames() {
  if (framesPromise) return framesPromise;
  framesPromise = (async () => {
    const bin = Uint8Array.from(atob(FRAME_DATA_B64), (c) => c.charCodeAt(0));
    const stream = new Blob([bin]).stream().pipeThrough(new DecompressionStream("gzip"));
    const text = await new Response(stream).text();
    const frames = text.split("\f");
    const first = frames[0] || "";
    const cols = first.indexOf("\n");
    const rows = first ? first.split("\n").length : 0;
    return { frames, cols, rows };
  })();
  return framesPromise;
}

class AsciiLartpc extends HTMLElement {
  static get observedAttributes() { return ["fps", "rotation", "paused"]; }

  connectedCallback() {
    this._connected = true;
    if (this.shadowRoot) {
      this._fit();
      if (this._frames && !this.hasAttribute("paused")) this._tick(performance.now());
      return;
    }

    const root = this.attachShadow({ mode: "open" });
    root.innerHTML = `
      <style>
        :host {
          display: block;
          background: var(--ascii-bg, transparent);
          color: var(--ascii-color, #111);
          font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, "Liberation Mono", monospace;
          line-height: 1;
          contain: content;
          position: relative;
          overflow: hidden;
          aspect-ratio: var(--ascii-aspect, 1 / 1);
          pointer-events: none;
          user-select: none;
        }
        .stage {
          display: flex;
          align-items: center;
          justify-content: center;
          width: 100%;
          height: 100%;
        }
        pre {
          margin: 0;
          white-space: pre;
          letter-spacing: 0;
          line-height: 1;
          font-variant-ligatures: none;
          font-feature-settings: "liga" 0, "calt" 0;
          pointer-events: none;
          user-select: none;
        }
      </style>
      <div class="stage"><pre part="grid"></pre></div>
    `;
    this.$pre = root.querySelector("pre");
    this.$stage = root.querySelector(".stage");

    this._frames = null;
    this._cols = 0;
    this._rows = 0;
    this._lastDraw = 0;
    this._lastIdx = -1;
    this._startTime = 0;
    this._raf = 0;

    loadFrames().then(({ frames, cols, rows }) => {
      if (!this.isConnected || !this._connected) return;
      this._frames = frames;
      this._cols = cols;
      this._rows = rows;
      this._fit();
      this._startTime = performance.now();
      if (!this.hasAttribute("paused")) this._tick(this._startTime);
    }).catch((err) => {
      if (this.isConnected && this._connected && this.$pre) this.$pre.textContent = String(err);
    });

    this._ro = new ResizeObserver(() => this._fit());
    this._ro.observe(this);
  }

  disconnectedCallback() {
    this._connected = false;
    cancelAnimationFrame(this._raf);
    this._raf = 0;
    this._ro?.disconnect();
  }

  attributeChangedCallback() {
    cancelAnimationFrame(this._raf);
    this._raf = 0;
    if (!this.isConnected || !this._connected || this.hasAttribute("paused")) return;
    if (this._frames) this._tick(performance.now());
  }

  get fps() {
    const v = parseFloat(this.getAttribute("fps"));
    return Number.isFinite(v) && v > 0 ? v : 60;
  }

  set fps(value) {
    if (value == null || value === false) this.removeAttribute("fps");
    else this.setAttribute("fps", String(value));
  }

  get rotation() {
    return this.getAttribute("rotation") ?? "";
  }

  set rotation(value) {
    if (value == null || value === false) this.removeAttribute("rotation");
    else this.setAttribute("rotation", String(value));
  }

  get rotationSeconds() {
    const v = parseFloat(this.getAttribute("rotation"));
    return Number.isFinite(v) && v > 0 ? v : 6;
  }

  _fit() {
    if (!this.$stage || !this._cols || !this._rows) return;
    const w = this.clientWidth || this.$stage.clientWidth;
    const h = this.clientHeight || this.$stage.clientHeight;
    if (!w || !h) return;
    // Monospace cells are ~0.6 wide vs tall. Fit the ASCII grid into the
    // available box (no extra padding).
    const charAspect = 0.605;
    const size = Math.max(1.5, Math.min(w / (this._cols * charAspect), h / this._rows));
    this.$pre.style.fontSize = size + "px";
  }

  _tick(now) {
    if (!this.isConnected || !this._connected || this.hasAttribute("paused") || !this._frames) return;
    const interval = 1000 / this.fps;
    if (now - this._lastDraw >= interval) {
      const elapsed = (now - this._startTime) / 1000;
      const N = this._frames.length;
      const idx = ((Math.floor((elapsed / this.rotationSeconds) * N) % N) + N) % N;
      if (idx !== this._lastIdx) {
        this.$pre.textContent = this._frames[idx];
        this._lastIdx = idx;
      }
      this._lastDraw = now;
    }
    this._raf = requestAnimationFrame((t) => this._tick(t));
  }
}

if (!customElements.get("ascii-lartpc")) {
  customElements.define("ascii-lartpc", AsciiLartpc);
}
